mapper.select:
SELECT *
FROM operation_log


        AND user_id = #{userId}


        AND user_role = #{userRole}


        AND operation_type = #{operationType}


        AND status = #{status}


        AND created_time  >=  #{startTime}


        AND created_time  <=  #{endTime}


ORDER BY created_time DESC, id DESC

SELECT *
FROM operation_log


        AND user_id = #{userId}


        AND user_role = #{userRole}


        AND operation_type = #{operationType}


        AND status = #{status}


        AND created_time  >=  #{startTime}


        AND created_time  <=  #{endTime}


ORDER BY created_time DESC, id DESC
LIMIT #{maxRows}

SELECT u.id AS userId, u.username AS userName, COALESCE( NULLIF(role_cfg.config_value, ''), CASE u.role WHEN 1 THEN 'ADMIN' WHEN 2 THEN 'STUDENT' WHEN 3 THEN 'TEACHER' WHEN 4 THEN 'ENTERPRISE' ELSE 'UNKNOWN' END ) AS userRole, COALESCE(ol.operation_count, 0) AS operationCount, ol.last_operation_time AS lastOperationTime, CAST( CASE WHEN status_cfg.config_value = '0' THEN 0 WHEN status_cfg.config_value = '1' THEN 1 ELSE COALESCE(u.status, 1) END AS SIGNED ) AS status FROM education_user_db.users u LEFT JOIN ( SELECT user_id, COUNT(1) AS operation_count, MAX(created_time) AS last_operation_time FROM operation_log WHERE user_id IS NOT NULL GROUP BY user_id ) ol ON ol.user_id = u.id LEFT JOIN system_config role_cfg ON role_cfg.config_key = CONCAT('admin.user.role.', u.id) LEFT JOIN system_config status_cfg ON status_cfg.config_key = CONCAT('admin.user.status.', u.id)
AND ( CAST(u.id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') )
AND COALESCE( NULLIF(role_cfg.config_value, ''), CASE u.role WHEN 1 THEN 'ADMIN' WHEN 2 THEN 'STUDENT' WHEN 3 THEN 'TEACHER' WHEN 4 THEN 'ENTERPRISE' ELSE 'UNKNOWN' END ) = #{userRole}
AND ( CASE WHEN status_cfg.config_value = '0' THEN 0 WHEN status_cfg.config_value = '1' THEN 1 ELSE COALESCE(u.status, 1) END ) = #{status}
ORDER BY ol.last_operation_time DESC, u.id DESC

SELECT *
FROM operation_log
WHERE user_id = #{userId}
ORDER BY created_time DESC, id DESC
LIMIT #{limitSize}

SELECT COUNT(1)
FROM operation_log
WHERE operation_type = #{operationType}

SELECT COUNT(1)
FROM operation_log
WHERE operation_type = #{operationType}
  AND status = #{status}

SELECT t.sql_digest AS sqlDigest, t.avg_time_ms AS avgTimeMs, t.max_time_ms AS maxTimeMs, t.execute_count AS executeCount, t.report_time AS reportTime FROM ( SELECT COALESCE(NULLIF(request_url, ''), CONCAT('OP:', IFNULL(operation_type, 'UNKNOWN'))) AS sql_digest, ROUND(AVG(IFNULL(execute_time, 0)), 2) AS avg_time_ms, ROUND(MAX(IFNULL(execute_time, 0)), 2) AS max_time_ms, COUNT(1) AS execute_count, MAX(created_time) AS report_time FROM operation_log WHERE IFNULL(execute_time, 0) >= #{slowThresholdMs}
AND ( request_url LIKE CONCAT('%', #{keyword}, '%') OR operation_type LIKE CONCAT('%', #{keyword}, '%') OR request_params LIKE CONCAT('%', #{keyword}, '%') )
GROUP BY COALESCE(NULLIF(request_url, ''), CONCAT('OP:', IFNULL(operation_type, 'UNKNOWN'))) ) t ORDER BY t.avg_time_ms DESC, t.report_time DESC
